attributes.cssVariables:
:root {
  /* Evangelion-inspired color palette */
  --background: oklch(0.98 0.005 260);
  --foreground: oklch(0.15 0.02 260);
  --card: oklch(0.99 0.003 260);
  --card-foreground: oklch(0.18 0.02 260);
  --popover: oklch(0.99 0.003 260);
  --popover-foreground: oklch(0.15 0.02 260);
  --primary: oklch(0.45 0.28 285); /* EVA-01 Purple */
  --primary-foreground: oklch(0.98 0 0);
  --secondary: oklch(0.55 0.25 145); /* EVA-01 Green */
  --secondary-foreground: oklch(0.15 0.02 145);
  --muted: oklch(0.92 0.015 260);
  --muted-foreground: oklch(0.45 0.02 260);
  --accent: oklch(0.65 0.22 45); /* Warning Orange */
  --accent-foreground: oklch(0.15 0.02 45);
  --destructive: oklch(0.55 0.3 25); /* Emergency Red */
  --destructive-foreground: oklch(0.98 0 0);
  --border: oklch(0.88 0.01 260);
  --input: oklch(0.99 0.003 260);
  --ring: oklch(0.45 0.28 285);
  --chart-1: oklch(0.45 0.28 285); /* Purple */
  --chart-2: oklch(0.55 0.25 145); /* Green */
  --chart-3: oklch(0.65 0.22 45); /* Orange */
  --chart-4: oklch(0.5 0.2 200); /* Blue */
  --chart-5: oklch(0.6 0.15 320); /* Pink */
  --sidebar: oklch(0.25 0.02 260);
  --sidebar-foreground: oklch(0.95 0.003 260);
  --sidebar-primary: oklch(0.45 0.28 285);
  --sidebar-primary-foreground: oklch(0.98 0 0);
  --sidebar-accent: oklch(0.65 0.22 45);
  --sidebar-accent-foreground: oklch(0.15 0.02 45);
  --sidebar-border: oklch(0.35 0.02 260);
  --sidebar-ring: oklch(0.45 0.28 285);
  --font-sans: 'Barlow', 'Oswald', 'Barlow Condensed', ui-sans-serif, sans-serif, system-ui;
  --font-serif: 'Bebas Neue', 'Oswald', serif;
  --font-mono: 'Share Tech Mono', 'Roboto Mono', ui-monospace, monospace;
  --radius: 0.125rem;
  --shadow-x: 0;
  --shadow-y: 2px;
  --shadow-blur: 8px;
  --shadow-spread: 0px;
  --shadow-opacity: 0.18;
  --shadow-color: oklch(0.3 0.15 285);
  --shadow-2xs: 0 1px 3px 0px hsl(285 60% 20% / 0.1);
  --shadow-xs: 0 1px 4px 0px hsl(285 60% 20% / 0.12);
  --shadow-sm: 0 2px 6px 0px hsl(285 60% 20% / 0.15),
    0 1px 3px -1px hsl(285 60% 20% / 0.12);
  --shadow: 0 2px 8px 0px hsl(285 60% 20% / 0.18), 0 1px 4px -1px hsl(285 60% 20% / 0.15);
  --shadow-md: 0 4px 12px 0px hsl(285 60% 20% / 0.18),
    0 2px 6px -1px hsl(285 60% 20% / 0.15);
  --shadow-lg: 0 8px 20px 0px hsl(285 60% 20% / 0.22),
    0 4px 10px -1px hsl(285 60% 20% / 0.18);
  --shadow-xl: 0 16px 32px 0px hsl(285 60% 20% / 0.25),
    0 8px 16px -1px hsl(285 60% 20% / 0.22);
  --shadow-2xl: 0 24px 48px 0px hsl(285 60% 20% / 0.3);
  --tracking-normal: 0.03em;
  --spacing: 0.25rem;
}

.dark {
  /* Dark mode with NERV control room aesthetic */
  --background: oklch(0.12 0.02 285);
  --foreground: oklch(0.95 0.003 145);
  --card: oklch(0.16 0.025 285);
  --card-foreground: oklch(0.95 0.003 145);
  --popover: oklch(0.18 0.025 285);
  --popover-foreground: oklch(0.95 0.003 145);
  --primary: oklch(0.55 0.32 285); /* Bright EVA-01 Purple */
  --primary-foreground: oklch(0.98 0 0);
  --secondary: oklch(0.65 0.28 145); /* Bright EVA-01 Green */
  --secondary-foreground: oklch(0.12 0.02 145);
  --muted: oklch(0.25 0.02 285);
  --muted-foreground: oklch(0.7 0.01 145);
  --accent: oklch(0.75 0.25 45); /* Bright Warning Orange */
  --accent-foreground: oklch(0.12 0.02 45);
  --destructive: oklch(0.65 0.35 25); /* Bright Emergency Red */
  --destructive-foreground: oklch(0.98 0 0);
  --border: oklch(0.3 0.02 285);
  --input: oklch(0.18 0.025 285);
  --ring: oklch(0.55 0.32 285);
  --chart-1: oklch(0.55 0.32 285);
  --chart-2: oklch(0.65 0.28 145);
  --chart-3: oklch(0.75 0.25 45);
  --chart-4: oklch(0.6 0.22 200);
  --chart-5: oklch(0.65 0.18 320);
  --sidebar: oklch(0.14 0.025 285);
  --sidebar-foreground: oklch(0.95 0.003 145);
  --sidebar-primary: oklch(0.55 0.32 285);
  --sidebar-primary-foreground: oklch(0.98 0 0);
  --sidebar-accent: oklch(0.75 0.25 45);
  --sidebar-accent-foreground: oklch(0.12 0.02 45);
  --sidebar-border: oklch(0.3 0.02 285);
  --sidebar-ring: oklch(0.55 0.32 285);
  --font-sans: 'Barlow', 'Oswald', 'Barlow Condensed', ui-sans-serif, sans-serif, system-ui;
  --font-serif: 'Bebas Neue', 'Oswald', serif;
  --font-mono: 'Share Tech Mono', 'Roboto Mono', ui-monospace, monospace;
  --radius: 0.125rem;
  --shadow-x: 0;
  --shadow-y: 2px;
  --shadow-blur: 12px;
  --shadow-spread: 0px;
  --shadow-opacity: 0.35;
  --shadow-color: oklch(0 0 0);
  --shadow-2xs: 0 1px 3px 0px hsl(285 60% 5% / 0.25);
  --shadow-xs: 0 1px 4px 0px hsl(285 60% 5% / 0.3);
  --shadow-sm: 0 2px 6px 0px hsl(285 60% 5% / 0.35),
    0 1px 3px -1px hsl(285 60% 5% / 0.3);
  --shadow: 0 2px 8px 0px hsl(285 60% 5% / 0.4), 0 1px 4px -1px hsl(285 60% 5% / 0.35);
  --shadow-md: 0 4px 12px 0px hsl(285 60% 5% / 0.4),
    0 2px 6px -1px hsl(285 60% 5% / 0.35);
  --shadow-lg: 0 8px 20px 0px hsl(285 60% 5% / 0.45),
    0 4px 10px -1px hsl(285 60% 5% / 0.4);
  --shadow-xl: 0 16px 32px 0px hsl(285 60% 5% / 0.5),
    0 8px 16px -1px hsl(285 60% 5% / 0.45);
  --shadow-2xl: 0 24px 48px 0px hsl(285 60% 5% / 0.55);
}
